using UnityEngine;

public sealed class Coin : MonoBehaviour
{
    [SerializeField] private int points = 1;

    public void Collect()
    {
        GameManager.Instance.AddScore(points);
        Destroy(gameObject);
    }
}

using UnityEngine;

public sealed class EnemyPatrol : MonoBehaviour
{
    [SerializeField] private Vector2 direction = Vector2.right;
    [SerializeField] private float speed = 3f;
    [SerializeField] private float distance = 4f;

    private Vector2 startPosition;

    private void Awake()
    {
        startPosition = transform.position;
        direction = direction.normalized;
    }

    private void Update()
    {
        float offset = Mathf.PingPong(Time.time * speed, distance) - distance * 0.5f;
        transform.position = startPosition + direction * offset;
    }
}

using UnityEngine;
using UnityEngine.SceneManagement;

public sealed class GameManager : MonoBehaviour
{
    public static GameManager Instance { get; private set; }

    [SerializeField] private PlayerController player;

    private int totalCoins;
    private int score;
    private bool gameEnded;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;
    }

    private void Start()
    {
        totalCoins = FindObjectsOfType<Coin>().Length;
        Debug.Log($"Coin Dash iniciado. Moedas na cena: {totalCoins}");
    }

    private void Update()
    {
        if (gameEnded && Input.GetKeyDown(KeyCode.R))
        {
            SceneManager.LoadScene(SceneManager.GetActiveScene().buildIndex);
        }
    }

    public void AddScore(int points)
    {
        if (gameEnded)
        {
            return;
        }

        score += points;
        Debug.Log($"Pontuação: {score}/{totalCoins}");

        if (score >= totalCoins)
        {
            WinGame();
        }
    }

    public void LoseGame()
    {
        if (gameEnded)
        {
            return;
        }

        gameEnded = true;
        SetPlayerEnabled(false);
        Debug.Log("Você perdeu! Aperte R para reiniciar.");
    }

    private void WinGame()
    {
        gameEnded = true;
        SetPlayerEnabled(false);
        Debug.Log("Você venceu! Aperte R para jogar novamente.");
    }

    private void SetPlayerEnabled(bool enabled)
    {
        if (player != null)
        {
            player.enabled = enabled;
        }
    }
}

using UnityEngine;

public sealed class PlayerController : MonoBehaviour
{
    [SerializeField] private float moveSpeed = 6f;

    private Rigidbody2D body;
    private Vector2 moveInput;

    private void Awake()
    {
        body = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        moveInput = new Vector2(Input.GetAxisRaw("Horizontal"), Input.GetAxisRaw("Vertical"));
        moveInput = Vector2.ClampMagnitude(moveInput, 1f);
    }

    private void FixedUpdate()
    {
        body.velocity = moveInput * moveSpeed;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (other.TryGetComponent(out Coin coin))
        {
            coin.Collect();
            return;
        }

        if (other.TryGetComponent(out EnemyPatrol _))
        {
            GameManager.Instance.LoseGame();
        }
    }
}

(() => {
  const canvas = document.getElementById("game");
  const ctx = canvas.getContext("2d");
  const hudScore = document.getElementById("score");
  const hudLives = document.getElementById("lives");
  const hudState = document.getElementById("state");
  const btnRestart = document.getElementById("restart");

  const keys = new Set();
  const world = {
    width: canvas.width,
    height: canvas.height,
    gravity: 0.65,
    friction: 0.82,
    cameraX: 0,
    levelWidth: 2600,
  };

  const playerStart = { x: 80, y: 330 };

  const player = {
    x: playerStart.x,
    y: playerStart.y,
    width: 32,
    height: 42,
    vx: 0,
    vy: 0,
    speed: 0.72,
    maxSpeed: 5.4,
    jumpPower: -13.2,
    grounded: false,
    invulnerable: 0,
    lives: 3,
    score: 0,
    won: false,
    dead: false,
  };

  const platforms = [
    { x: 0, y: 520, width: 620, height: 60 },
    { x: 720, y: 500, width: 420, height: 80 },
    { x: 1250, y: 470, width: 360, height: 110 },
    { x: 1700, y: 520, width: 390, height: 60 },
    { x: 2200, y: 490, width: 390, height: 90 },
    { x: 320, y: 405, width: 150, height: 20 },
    { x: 850, y: 380, width: 150, height: 20 },
    { x: 1420, y: 340, width: 170, height: 20 },
    { x: 1900, y: 390, width: 160, height: 20 },
  ];

  const coins = [
    { x: 360, y: 360, taken: false },
    { x: 440, y: 360, taken: false },
    { x: 900, y: 335, taken: false },
    { x: 980, y: 335, taken: false },
    { x: 1320, y: 420, taken: false },
    { x: 1500, y: 295, taken: false },
    { x: 1940, y: 345, taken: false },
    { x: 2020, y: 345, taken: false },
    { x: 2300, y: 445, taken: false },
    { x: 2440, y: 445, taken: false },
  ];

  const enemies = [
    { x: 760, y: 462, width: 34, height: 38, vx: 1.6, min: 740, max: 1090 },

{ x: 1310, y: 432, width: 34, height: 38, vx: 1.8, min: 1260, max: 1570 },
    { x: 1740, y: 482, width: 34, height: 38, vx: 1.5, min: 1710, max: 2050 },
    { x: 2250, y: 452, width: 34, height: 38, vx: 2.0, min: 2220, max: 2530 },
  ];

  const goal = { x: 2520, y: 390, width: 42, height: 100 };

  function resetGame() {
    player.x = playerStart.x;
    player.y = playerStart.y;
    player.vx = 0;
    player.vy = 0;
    player.grounded = false;
    player.invulnerable = 0;
    player.lives = 3;
    player.score = 0;
    player.won = false;
    player.dead = false;
    world.cameraX = 0;

    coins.forEach((coin) => {
      coin.taken = false;
    });

    hudState.textContent = "Pegue moedas, evite inimigos e alcance a bandeira.";
    updateHud();
  }

  function respawnPlayer() {
    player.x = playerStart.x;
    player.y = playerStart.y;
    player.vx = 0;
    player.vy = 0;
    player.invulnerable = 100;
  }

  function updateHud() {
    hudScore.textContent = String(player.score);
    hudLives.textContent = String(player.lives);
  }

  function rectsOverlap(a, b) {
    return (
      a.x < b.x + b.width &&
      a.x + a.width > b.x &&
      a.y < b.y + b.height &&
      a.y + a.height > b.y
    );
  }

  function coinOverlap(coin) {
    const centerX = coin.x + 10;
    const centerY = coin.y + 10;
    return (
      centerX > player.x &&
      centerX < player.x + player.width &&
      centerY > player.y &&
      centerY < player.y + player.height
    );
  }

  function handleInput() {
    if (player.dead || player.won) return;

    const left = keys.has("ArrowLeft") || keys.has("KeyA");
    const right = keys.has("ArrowRight") || keys.has("KeyD");
    const jump = keys.has("Space") || keys.has("ArrowUp") || keys.has("KeyW");

if (left) player.vx -= player.speed;
    if (right) player.vx += player.speed;

    player.vx = Math.max(-player.maxSpeed, Math.min(player.maxSpeed, player.vx));

    if (jump && player.grounded) {
      player.vy = player.jumpPower;
      player.grounded = false;
    }
  }


  function movePlayer() {
    player.vx *= world.friction;
    player.vy += world.gravity;

    player.x += player.vx;
    player.x = Math.max(0, Math.min(world.levelWidth - player.width, player.x));

    for (const platform of platforms) {
      if (!rectsOverlap(player, platform)) continue;

      if (player.vx > 0) player.x = platform.x - player.width;
      if (player.vx < 0) player.x = platform.x + platform.width;
      player.vx = 0;
    }

    player.y += player.vy;
    player.grounded = false;

    for (const platform of platforms) {
      if (!rectsOverlap(player, platform)) continue;

      if (player.vy > 0) {
        player.y = platform.y - player.height;
        player.vy = 0;
        player.grounded = true;
      } else if (player.vy < 0) {
        player.y = platform.y + platform.height;
        player.vy = 0;
      }
    }

    if (player.y > world.height + 160) {
      damagePlayer();
    }

    world.cameraX = Math.max(
      0,
      Math.min(world.levelWidth - world.width, player.x - world.width * 0.38)
    );
  }

  function updateEnemies() {
    enemies.forEach((enemy) => {
      enemy.x += enemy.vx;
      if (enemy.x < enemy.min || enemy.x > enemy.max) {
        enemy.vx *= -1;
        enemy.x += enemy.vx;
      }

      if (!player.dead && !player.won && rectsOverlap(player, enemy)) {
        if (player.vy > 2 && player.y + player.height - enemy.y < 18) {
          enemy.x = enemy.min - 200;
          player.vy = -8.5;
          player.score += 50;

updateHud();
        } else {
          damagePlayer();
        }
      }
    });
  }

  function damagePlayer() {
    if (player.invulnerable > 0 || player.dead || player.won) return;

    player.lives -= 1;
    updateHud();

    if (player.lives <= 0) {
      player.dead = true;
      hudState.textContent = "Fim de jogo! Clique em reiniciar para tentar de novo.";
      return;
    }

    hudState.textContent = "Você levou dano! Continue tentando.";
    respawnPlayer();
  }

  function collectCoins() {
    coins.forEach((coin) => {
      if (!coin.taken && coinOverlap(coin)) {
        coin.taken = true;
        player.score += 10;
        updateHud();
      }
    });
  }

  function checkGoal() {
    if (!player.won && rectsOverlap(player, goal)) {
      player.won = true;
      player.score += 100;
      hudState.textContent = "Vitória! Você completou o jogo jogável.";
      updateHud();
    }
  }

  function update() {
    handleInput();

    if (!player.dead && !player.won) {
      movePlayer();
      updateEnemies();
      collectCoins();
      checkGoal();
      if (player.invulnerable > 0) player.invulnerable -= 1;
    }
  }

  function drawBackground() {
    const gradient = ctx.createLinearGradient(0, 0, 0, world.height);
    gradient.addColorStop(0, "#7dd3fc");
    gradient.addColorStop(0.58, "#bfdbfe");
    gradient.addColorStop(1, "#d9f99d");
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, world.width, world.height);

    ctx.fillStyle = "rgba(255,255,255,0.75)";
    for (let i = 0; i < 9; i += 1) {
      const cloudX = (i * 330 - world.cameraX * 0.35) % (world.width + 180) - 90;
      const cloudY = 70 + (i % 3) * 48;
      ctx.beginPath();
      ctx.arc(cloudX, cloudY, 28, 0, Math.PI * 2);

ctx.arc(cloudX + 28, cloudY - 12, 34, 0, Math.PI * 2);
      ctx.arc(cloudX + 62, cloudY, 25, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  function drawPlatforms() {
    platforms.forEach((platform) => {
      const x = platform.x - world.cameraX;
      ctx.fillStyle = "#166534";
      ctx.fillRect(x, platform.y, platform.width, platform.height);
      ctx.fillStyle = "#22c55e";
      ctx.fillRect(x, platform.y, platform.width, 12);
      ctx.fillStyle = "rgba(0,0,0,0.15)";
      ctx.fillRect(x, platform.y + platform.height - 8, platform.width, 8);
    });
  }

  function drawCoins() {
    coins.forEach((coin) => {
      if (coin.taken) return;
      const x = coin.x - world.cameraX;
      ctx.fillStyle = "#facc15";
      ctx.beginPath();
      ctx.arc(x + 10, coin.y + 10, 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = "#ca8a04";
      ctx.lineWidth = 3;
      ctx.stroke();

﻿:root {
  color-scheme: dark;
  --bg: #09111f;
  --panel: rgba(14, 25, 45, 0.86);
  --text: #edf6ff;
  --muted: #9fb4ce;
  --accent: #45e6a8;
  --danger: #ff4d6d;
  --gold: #ffd166;
}

* { box-sizing: border-box; }
body {
  margin: 0;
  min-height: 100vh;
  font-family: Inter, Segoe UI, system-ui, sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at top left, rgba(69, 230, 168, 0.2), transparent 28rem),
    linear-gradient(135deg, #08101d 0%, #111f36 100%);
}
.shell {
  width: min(1180px, calc(100vw - 32px));
  margin: 0 auto;
  padding: 28px 0;
}
.panel, .game-card {
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 24px;
  background: var(--panel);
  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.32);
}
.hero {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 24px;
  margin-bottom: 18px;
}
.eyebrow {
  margin: 0 0 8px;
  color: var(--accent);
  font-weight: 800;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}
h1 {
  margin: 0;
  font-size: clamp(2rem, 5vw, 4rem);
}
.subtitle {
  margin: 8px 0 0;
  color: var(--muted);
  max-width: 620px;
}
.actions {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: flex-end;
}
button {
  border: 0;
  border-radius: 999px;
  padding: 12px 18px;
  color: #06111c;
  background: var(--accent);
  font-weight: 800;
  cursor: pointer;
}
button.secondary { background: var(--gold); }
button.ghost {
  color: var(--text);
  background: rgba(255, 255, 255, 0.1);
}
.game-card {
  display: grid;
  grid-template-columns: 1fr 220px;
  gap: 16px;
  padding: 16px;
}
canvas {
  width: 100%;
  max-height: 72vh;
  border-radius: 18px;
  background: #111c2e;
  outline: 1px solid rgba(255, 255, 255, 0.1);
}
.hud {
  display: grid;
  gap: 12px;

align-content: start;
}
.hud div {
  padding: 14px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.08);
}
.hud strong, .hud span { display: block; }
.hud strong { color: var(--muted); font-size: 0.85rem; }
.hud span { margin-top: 6px; font-size: 1.2rem; font-weight: 800; }
.instructions {
  margin-top: 18px;
  padding: 20px 24px;
}
.instructions h2 { margin: 0 0 10px; }
.instructions ul { margin: 0; padding-left: 22px; color: var(--muted); }
kbd {
  padding: 2px 7px;
  border-radius: 6px;
  color: var(--text);
  background: rgba(255, 255, 255, 0.12);
}
@media (max-width: 860px) {
  .hero, .game-card { grid-template-columns: 1fr; }
  .hero { align-items: stretch; flex-direction: column; }
  .actions { justify-content: flex-start; }
}
